import{_ as o,o as n,c as r,a0 as t}from"./chunks/framework.BjpW4enL.js";const m=JSON.parse('{"title":"Anchored Summary — Session 2026-06-25","description":"","frontmatter":{},"headers":[],"relativePath":"99_Log_e_Sessoes/sessions/2026-06-25.md","filePath":"99_Log_e_Sessoes/sessions/2026-06-25.md","lastUpdated":1782592277000}'),a={name:"99_Log_e_Sessoes/sessions/2026-06-25.md"};function s(i,e,l,c,d,u){return n(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="anchored-summary-—-session-2026-06-25" tabindex="-1">Anchored Summary — Session 2026-06-25 <a class="header-anchor" href="#anchored-summary-—-session-2026-06-25" aria-label="Permalink to &quot;Anchored Summary — Session 2026-06-25&quot;">​</a></h1><h2 id="bug-qdrant-collection-vector-schema-mismatch" tabindex="-1">Bug: Qdrant Collection Vector Schema Mismatch <a class="header-anchor" href="#bug-qdrant-collection-vector-schema-mismatch" aria-label="Permalink to &quot;Bug: Qdrant Collection Vector Schema Mismatch&quot;">​</a></h2><ul><li><strong>Problem</strong>: <code>nexus_ghost</code> and <code>nexus_reflections</code> collections had unnamed vectors; all code sends <code>{&quot;text_dense&quot;: vector}</code>.</li><li><strong>Root cause</strong>: Created during init without named vector. Only <code>nexus_ast</code> worked (manually created with correct schema).</li><li><strong>Fix</strong>: Recreated both collections with <code>text_dense</code> (768d, Cosine).</li><li><strong>Status</strong>: All 3 collections now consistent.</li></ul><h2 id="fix-ollama-container-oom" tabindex="-1">Fix: Ollama Container OOM <a class="header-anchor" href="#fix-ollama-container-oom" aria-label="Permalink to &quot;Fix: Ollama Container OOM&quot;">​</a></h2><ul><li><strong>Problem</strong>: Ollama container (4G RAM limit) OOM-killed when loading both models.</li><li><strong>Root cause</strong>: 6GB VRAM sufficient. Bottleneck was 4G <strong>container RAM</strong> — non-offloaded layers (~560MB) + nomic (~200MB) + Ollama overhead exceeded 4G.</li><li><strong>Fix</strong>: <code>docker-compose.standalone.yml</code> → 4G → 8G.</li><li><strong>GPU</strong>: 29 layers offloaded (GTX 1660S, 6GB VRAM). Embedding runs on CPU.</li></ul><h2 id="bug-l2-phase-2-blocked-by-concurrency-pile-up" tabindex="-1">Bug: L2 Phase 2 Blocked by Concurrency Pile-up <a class="header-anchor" href="#bug-l2-phase-2-blocked-by-concurrency-pile-up" aria-label="Permalink to &quot;Bug: L2 Phase 2 Blocked by Concurrency Pile-up&quot;">​</a></h2><ul><li><strong>Problem</strong>: Multiple concurrent <code>run_l2_enrichment()</code> (POST /enrich + watcher + background loop) fighting over 2-permit semaphore. Phase 1 never drained → Phase 2 never executed.</li><li><strong>Evidence</strong>: 357 L2 rows in PG, 0 in Qdrant. No &quot;phase 2&quot; logs since restart.</li><li><strong>Fix</strong>: <code>TRUNCATE blobs CASCADE</code> + Qdrant clear + restart. Background loops alone process cleanly.</li><li><strong>Result</strong>: Phase 2 runs every cycle now.</li></ul><h2 id="pipeline-performance-fresh-ingest" tabindex="-1">Pipeline Performance (fresh ingest) <a class="header-anchor" href="#pipeline-performance-fresh-ingest" aria-label="Permalink to &quot;Pipeline Performance (fresh ingest)&quot;">​</a></h2><ul><li>266s uptime: 13 blobs ingested, 238 L0, 11 L1, 7 L2</li><li>GPU: 69-85% during L2 gen, 1780 MiB VRAM</li><li>RAM: ~5.3G/7.6G used, 2.3G available, 1.3G zram</li><li><strong>Idle GPU pattern</strong>: L1 (CPU) outpaces L2 (GPU). Expected in dev.</li></ul><h2 id="agents-md-restructured" tabindex="-1">AGENTS.md Restructured <a class="header-anchor" href="#agents-md-restructured" aria-label="Permalink to &quot;AGENTS.md Restructured&quot;">​</a></h2><ul><li>Slimmed to pure onboarding (Golden Rule + MCP primitives + T4 overview)</li><li>Extracted sections → <code>docs/operations/</code>, <code>docs/guides/</code>, <code>docs/sessions/</code></li></ul>',11)])])}const g=o(a,[["render",s]]);export{m as __pageData,g as default};
